#include <iostream>
#include <iomanip>
#include <string>
#include <sstream>

std::string formatReceiptLine(std::string name, double price,
                               std::string symbol = "$", double discount = 0.0) {
    if (discount == 0.0) {
        std::ostringstream oss; oss << symbol << std::fixed << std::setprecision(2) << price << " — " << name; return oss.str();
    } else {
        double discounted = price * (1.0 - discount / 100.0);
        std::ostringstream oss; oss << symbol << std::fixed << std::setprecision(2) << discounted << " — " << name << " (" << std::fixed << std::setprecision(1) << discount << "% off)"; return oss.str();
    }
}

int main() {
    int n;
    std::cin >> n;
    std::cin.ignore();

    for (int i = 0; i < n; ++i) {
        std::string line;
        std::getline(std::cin, line);
        std::istringstream ss(line);

        std::string name, symbol;
        double price, discount;

        ss >> name >> price;
        if (ss >> symbol) {
            if (ss >> discount) {
                std::cout << formatReceiptLine(name, price, symbol, discount) << "\n";
            } else {
                std::cout << formatReceiptLine(name, price, symbol) << "\n";
            }
        } else {
            std::cout << formatReceiptLine(name, price) << "\n";
