#include <iostream>

template <typename T>
void swapValues(T& a, T& b)
{
    T temp{ a };
    a = b;
    b = temp;
}

void describe(int a, int b)
{
    (void)a; (void)b;
    std::cout << "Type: integer pair\n";
}

void describe(double a, double b)
{
    (void)a; (void)b;
    std::cout << "Type: double pair\n";
}

int main()
{
    int n{};
    std::cin >> n;

    for (int i{}; i < n; ++i)
    {
        char tag{};
        std::cin >> tag;

        if (tag == 'i')
        {
            int a{}, b{};
            std::cin >> a >> b;
            swapValues(a, b);
            std::cout << "Swapped: " << a << " " << b << "\n";
            describe(a, b);
        }
        else // 'd'
        {
            double a{}, b{};
            std::cin >> a >> b;
            swapValues(a, b);
            std::cout << "Swapped: " << a << " " << b << "\n";
            describe(a, b);
        }
    }

    return 0;
}

